package gui; import db.DBConnection; import javax.swing.*; import java.awt.*; import java.io.File; import java.io.FileInputStream; import java.sql.*; public class RegisterForm extends JFrame { JTextField txtUsername, txtFirst, txtLast, txtAge, txtAddress, txtDOB; JPasswordField txtPassword; byte[] photoBytes; public RegisterForm() { setTitle("User Registration"); setSize(500, 450); setLayout(new GridLayout(10, 2, 10, 10)); setLocationRelativeTo(null); getContentPane().setBackground(new Color(250, 250, 250)); txtUsername = new JTextField(); txtPassword = new JPasswordField(); txtFirst = new JTextField(); txtLast = new JTextField(); txtDOB = new JTextField(); txtAge = new JTextField(); txtAddress = new JTextField(); JButton btnPhoto = new JButton("Upload Photo"); JButton btnSave = new JButton("Save"); JButton btnBack = new JButton("Back"); btnPhoto.setBackground(new Color(206, 115, 244)); btnPhoto.setForeground(Color.WHITE); btnSave.setBackground(new Color(116, 189, 239)); btnSave.setForeground(Color.WHITE); btnBack.setBackground(new Color(245, 109, 194)); btnBack.setForeground(Color.WHITE); add(new JLabel("Username:")); add(txtUsername); add(new JLabel("Password:")); add(txtPassword); add(new JLabel("First Name:")); add(txtFirst); add(new JLabel("Last Name:")); add(txtLast); add(new JLabel("Date of Birth:")); add(txtDOB); add(new JLabel("Age:")); add(txtAge); add(new JLabel("Address:")); add(txtAddress); add(btnPhoto); add(new JLabel("")); add(btnSave); add(btnBack); btnPhoto.addActionListener(e -> uploadPhoto()); btnSave.addActionListener(e -> saveUser()); btnBack.addActionListener(e -> dispose()); setVisible(true); } private void uploadPhoto() { try { JFileChooser chooser = new JFileChooser(); chooser.showOpenDialog(this); File file = chooser.getSelectedFile(); FileInputStream fis = new FileInputStream(file); photoBytes = fis.readAllBytes(); } catch (Exception e) { e.printStackTrace(); } } private void saveUser() { String sql = """ INSERT INTO Users(username,password,first_name,last_name,email,date_of_birth,photo) VALUES(?,?,?,?,?,?,?) """; try (Connection conn = DBConnection.getConnection(); PreparedStatement ps = conn.prepareStatement(sql)) { ps.setString(1, txtUsername.getText()); ps.setString(2, new String(txtPassword.getPassword())); ps.setString(3, txtFirst.getText()); ps.setString(4, txtLast.getText()); ps.setString(5, txtUsername.getText() + "@mail.com"); ps.setString(6, txtDOB.getText()); ps.setBytes(7, photoBytes); ps.executeUpdate(); JOptionPane.showMessageDialog(this, "User registered successfully!"); } catch (Exception e) { e.printStackTrace(); } } }
